sys_variable_value.value:
(function execute(inputs, outputs) {

  var int_email = inputs.internal_email;

  var ext_email = inputs.external_email;

  if (int_email) {
  	outputs.sender = int_email;
} else if (ext_email) {
  	outputs.sender = ext_email;
}; 

})(inputs, outputs);

